class Tag(val name: String) {
    private val children = mutableListOf<Tag>()
    var text: String = ""

    fun tag(name: String, block: Tag.() -> Unit): Tag {
        val child = Tag(name).apply(block)
        children.add(child)
        return child
    }

    fun build(): String = if (children.isEmpty())
        "<$name>$text</$name>"
    else
        "<$name>${children.joinToString("") { it.build() }}</$name>"
}

fun html(block: Tag.() -> Unit) = Tag("html").apply(block).build()

